oxy_webhelp_navlinks = {"sql_server_databases-d30753e29737":{"topics":[{"title":"Set up Microsoft SQL Server","shortdesc":"<p class=\"shortdesc\">You can set up Microsoft SQL Server in RSC to start protecting Microsoft SQL Server         workloads.<\/p>","href":"saas\/mssql_setup_mssql.html","attributes":{"data-id":"mssql_setup_mssql"},"menu":{"hasChildren":false},"tocID":"mssql_setup_mssql-d30753e29748","next":"mssql_setup_mssql-d30753e29748"},{"title":"Microsoft SQL Server database details","shortdesc":"<p class=\"shortdesc\">The Microsoft SQL Server database details page provides detailed information about the         database, its protection status, Live Mounts, available snapshots, database events and         snapshots.<\/p>","href":"saas\/mssql_database_details.html","attributes":{"data-id":"mssql_database_details"},"menu":{"hasChildren":false},"tocID":"mssql_database_details-d30753e29839","next":"mssql_database_details-d30753e29839"},{"title":"Manage Microsoft SQL Server database hosts","shortdesc":"<p class=\"shortdesc\">After adding a Microsoft SQL Server host, you can manage the host by refreshing         metadata, updating certificates, editing host settings, modifying Change Block Tracking, or         deleting the host.<\/p>","href":"saas\/mssql_manage_mssql_database_hosts.html","attributes":{"data-id":"mssql_manage_mssql_database_hosts"},"menu":{"hasChildren":false},"tocID":"mssql_manage_mssql_database_hosts-d30753e29883","next":"mssql_manage_mssql_database_hosts-d30753e29883"},{"title":"Protect Microsoft SQL Server databases","shortdesc":"<p class=\"shortdesc\">After adding a Windows Server host to a Rubrik cluster, the Microsoft SQL Server         databases on that host can be managed through the web UI.<\/p>","href":"common\/sql_protect_mssql_databases.html","attributes":{"data-id":"sql_protect_mssql_databases"},"menu":{"hasChildren":false},"tocID":"sql_protect_mssql_databases-d30753e29919","next":"sql_protect_mssql_databases-d30753e29919"},{"title":"SQL Change Block Tracking","shortdesc":"<p class=\"shortdesc\">Change Block Tracking uses a filter driver to track SQL database file changes as they     happen.<\/p>","href":"common\/sql_change_block_tracking.html","attributes":{"data-id":"sql_change_block_tracking"},"menu":{"hasChildren":false},"tocID":"sql_change_block_tracking-d30753e30007","next":"sql_change_block_tracking-d30753e30007"},{"title":"Recover Microsoft SQL Server databases","shortdesc":"<p class=\"shortdesc\">You can use a Rubrik cluster to manage backup, restore, and recovery of Microsoft SQL Server         databases.<\/p>","href":"saas\/mssql_recover_mssql_databases.html","attributes":{"data-id":"mssql_recover_mssql_databases"},"menu":{"hasChildren":false},"tocID":"mssql_recover_mssql_databases-d30753e30040","next":"mssql_recover_mssql_databases-d30753e30040"},{"title":"Microsoft SQL Server log shipping","shortdesc":"<p class=\"shortdesc\">Automatically send transaction log backups from a primary database running on a primary     server instance to one or more secondary databases running on separate secondary server     instances by using the Microsoft SQL Server log shipping feature.<\/p>","href":"common\/sql_server_log_shipping.html","attributes":{"data-id":"sql_server_log_shipping"},"menu":{"hasChildren":false},"tocID":"sql_server_log_shipping-d30753e30208","next":"sql_server_log_shipping-d30753e30208"},{"title":"Windows Server Failover Clustering","shortdesc":"<p class=\"shortdesc\">The Rubrik cluster provides protection for Windows Server Failover Clustering at the         failover cluster instance level.<\/p>","href":"saas\/mssql_windows_server_failover_clustering.html","attributes":{"data-id":"mssql_windows_server_failover_clustering"},"menu":{"hasChildren":false},"tocID":"mssql_windows_server_failover_clustering-d30753e30274","next":"mssql_windows_server_failover_clustering-d30753e30274"},{"title":"Always On Availability Groups","shortdesc":"<p class=\"shortdesc\">The Rubrik cluster supports data protection for availability databases in an Always On     availability group.<\/p>","href":"common\/sql_always_on_availability_groups.html","attributes":{"data-id":"sql_always_on_availability_groups"},"menu":{"hasChildren":false},"tocID":"sql_always_on_availability_groups-d30753e30362","next":"sql_always_on_availability_groups-d30753e30362"}]}};